import{_ as a,o as e,c as r,a2 as l}from"./chunks/framework.Crpw6aS5.js";const u=JSON.parse('{"title":"比亚迪","description":"","frontmatter":{"title":"比亚迪"},"headers":[],"relativePath":"03_companies/比亚迪.md","filePath":"03_companies/比亚迪.md"}'),i={name:"03_companies/比亚迪.md"};function o(n,t,d,h,s,c){return e(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="比亚迪" tabindex="-1">比亚迪 <a class="header-anchor" href="#比亚迪" aria-label="Permalink to &quot;比亚迪&quot;">​</a></h1><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><ul><li><strong>首次提及</strong>: 2008年</li><li><strong>持股情况</strong>: <ul><li>2008年：持股10%</li><li>2017年：持股比例约8.2%</li><li>2020年：持有8.2%股权</li><li>2021年：持有7.7%股权（由BHE持有）</li></ul></li><li><strong>行业</strong>: 新能源汽车、电池</li><li><strong>英文名</strong>: BYD Co. Ltd.</li><li><strong>总部</strong>: 中国深圳</li></ul><h2 id="巴菲特论述" tabindex="-1">巴菲特论述 <a class="header-anchor" href="#巴菲特论述" aria-label="Permalink to &quot;巴菲特论述&quot;">​</a></h2><p>2008年投资比亚迪，持股10%。这是巴菲特对中国新能源领域的重要投资，也是伯克希尔少数的海外股票投资之一。</p><p>比亚迪是中国领先的电动车和电池公司。2020年持股成本2.32亿美元，市值达58.97亿美元；2021年市值增长至76.93亿美元。</p><p>由伯克希尔能源(BHE)持有，伯克希尔股东享有91.1%权益。2020年成为伯克希尔&quot;十五大股权持仓&quot;之一。</p><h2 id="投资意义" tabindex="-1">投资意义 <a class="header-anchor" href="#投资意义" aria-label="Permalink to &quot;投资意义&quot;">​</a></h2><p>这次投资展示了巴菲特对新能源汽车领域的看好。比亚迪创始人王传福的技术创新能力和企业的成本优势，是巴菲特做出投资决策的重要因素。这笔投资回报丰厚，展现了巴菲特在新兴产业领域的判断力。</p><h2 id="市值变化" tabindex="-1">市值变化 <a class="header-anchor" href="#市值变化" aria-label="Permalink to &quot;市值变化&quot;">​</a></h2><table tabindex="0"><thead><tr><th>年份</th><th>持股成本</th><th>市值</th></tr></thead><tbody><tr><td>2020年</td><td>2.32亿美元</td><td>58.97亿美元</td></tr><tr><td>2021年</td><td>-</td><td>76.93亿美元</td></tr></tbody></table><h2 id="关联年份" tabindex="-1">关联年份 <a class="header-anchor" href="#关联年份" aria-label="Permalink to &quot;关联年份&quot;">​</a></h2><p>2008, 2017, 2020, 2021</p><h2 id="相关信件" tabindex="-1">相关信件 <a class="header-anchor" href="#相关信件" aria-label="Permalink to &quot;相关信件&quot;">​</a></h2><ul><li><a href="./../01_letters/2020年/翻译.html">2020年</a></li></ul>',15)])])}const p=a(i,[["render",o]]);export{u as __pageData,p as default};
